// Decode a factor string into a flat Int8Array of cell values.
export function decodeFactor(s: string): Int8Array {
	const out = new Int8Array(s.length);
	for (let i = 0; i < s.length; i++) {
		const c = s.charCodeAt(i);
		// '+' = 43, '-' = 45, '.' = 46
		out[i] = c === 43 ? 1 : c === 45 ? -1 : 0;
	}
	return out;
}

export function findAlphaTensorPreset(m: number, n: number, p: number): AlphaTensorPreset | null {
	return ALPHATENSOR_PRESETS.find((s) => s.m === m && s.n === n && s.p === p) ?? null;
}
